CustomField.formula:
IF(
    /* tungnm37: Nếu có assignment (FEC_Assignment_Users__c có giá trị) VÀ owner là User (không phải Queue) thì return empty */
    /* Khi owner là Queue (manual flow route đến queue), vẫn hiển thị Queue name */
    NOT(ISBLANK(FEC_Assignment_Users__c)) && ISBLANK(Owner:Queue.Id),
    '',
    /* Nếu không có assignment hoặc owner là Queue thì hiển thị owner như cũ */
    IF( Or(RecordType.Name = 'Customer Case', RecordType.Name = 'Internal Case'),
        (IF(ISBLANK(Owner:Queue.Id),
            LEFT(Owner:User.Email,FIND("@", Owner:User.Email) - 1),
            Owner:Queue.Name)),
        '')
)
